import json
from datetime import datetime

# Get file path from storage variable
file_path = locals()['var_function-call-16423644886177447864']

with open(file_path, 'r') as f:
    history = json.load(f)

start_date = datetime(2022, 4, 10)
end_date = datetime(2023, 4, 10)

def parse_date(d_str):
    try:
        # 2023-09-07T16:30:00.000+0000
        # Removing timezone for naive comparison if needed, or handle offsets
        # The offset +0000 is UTC.
        dt = datetime.strptime(d_str, "%Y-%m-%dT%H:%M:%S.%f%z")
        # Convert to naive or ensure start/end are aware.
        # Let's make start/end aware (UTC) or make dt naive.
        # Making dt naive (ignoring tz) is easier if all are UTC.
        return dt.replace(tzinfo=None)
    except ValueError:
        try:
             dt = datetime.strptime(d_str, "%Y-%m-%dT%H:%M:%S%z")
             return dt.replace(tzinfo=None)
        except:
             return None

def clean_id(i):
    if not i or i == 'None':
        return None
    s = i.strip()
    if s.startswith('#'):
        s = s[1:]
    return s

transfer_counts = {}
handled_agents = set()

for record in history:
    d_str = record.get('createddate')
    if not d_str:
        continue

    dt = parse_date(d_str)
    if not dt:
        continue

    # Filter date range
    if start_date <= dt <= end_date:
        old_val = clean_id(record.get('oldvalue__c'))
        new_val = clean_id(record.get('newvalue__c'))

        # Count transfers (sender)
        if old_val:
            transfer_counts[old_val] = transfer_counts.get(old_val, 0) + 1

        # Track handled agents (receiver)
        if new_val:
            handled_agents.add(new_val)

min_transfers = float('inf')
candidate_agents = []

if not handled_agents:
    result = []
else:
    for agent in handled_agents:
        count = transfer_counts.get(agent, 0)
        if count < min_transfers:
            min_transfers = count
            candidate_agents = [agent]
        elif count == min_transfers:
            candidate_agents.append(agent)
    candidate_agents.sort()
    result = candidate_agents

print("__RESULT__:")
print(json.dumps(result))

