def clean_id(i):
    if not i or i == 'None':
        return None
    s = i.strip()
    if s.startswith('#'):
        s = s[1:]
    return s

transfer_counts = {}
handled_cases = {} # agent -> set of case_ids
handled_agents = set()

for record in history:
    d_str = record.get('createddate')
    if not d_str:
        continue

    dt = parse_date(d_str)
    if not dt:
